mapper.select:
SELECT EXISTS(
    SELECT 1
      FROM com.tn_sys_authrt_role_mpng
     WHERE authrt_id = #{authrtId}
       AND role_id   = #{roleId}
       AND NOW() BETWEEN use_bgng_dt AND use_end_dt
)

mapper.update:
UPDATE com.tn_sys_authrt_role_mpng
   SET use_end_dt       = NOW() - INTERVAL '1 minute',
       last_chg_dt      = NOW(),
       last_chg_user_id = #{lastChgUserId}
 WHERE authrt_id = #{authrtId}
   AND role_id   = #{roleId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
